import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { map } from 'rxjs/operators';
import { Account, Contact, Opportunity, OPPORTUNITY_STAGES } from '../../core/models/crm.models';

@Component({
  selector: 'app-account-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule],
  templateUrl: './account-detail.component.html',
  styleUrl: './account-detail.component.css',
})
export class AccountDetailComponent {
  private route = inject(ActivatedRoute);
  private fb = inject(FormBuilder);

  readonly stages = OPPORTUNITY_STAGES;

  readonly id = toSignal(this.route.paramMap.pipe(map((p) => p.get('id'))), {
    initialValue: this.route.snapshot.paramMap.get('id'),
  });

  // Backend-provided data. mockup_cleaner empties these; service_agent wires
  // them to AccountService.get(id) in ngOnInit().
  accounts = signal<Account[]>([
    { id: '1', name: 'Globex Corporation', industry: 'Manufacturing', website: 'globex.com', phone: '+1 415 555 0132' },
    { id: '2', name: 'Initech', industry: 'Software', website: 'initech.io', phone: '+1 512 555 0148' },
    { id: '3', name: 'Umbrella Co', industry: 'Healthcare', website: 'umbrella.co', phone: '+1 212 555 0199' },
    { id: '4', name: 'Soylent Industries', industry: 'Food & Beverage', website: 'soylent.com', phone: '+1 305 555 0170' },
  ]);

  relatedContacts = signal<Contact[]>([
    { id: 'c1', name: 'Hank Scorpio', email: 'hank@globex.com', phone: '+1 415 555 0140', accountId: '1' },
    { id: 'c2', name: 'Mona Vale', email: 'mona@globex.com', accountId: '1' },
    { id: 'c3', name: 'Peter Gibbons', email: 'peter@initech.io', accountId: '2' },
  ]);

  relatedOpportunities = signal<Opportunity[]>([
    { id: 'o1', name: 'Globex — Platform license', amount: 48000, stage: 'Proposal', accountId: '1', closeDate: '2026-08-01' },
    { id: 'o2', name: 'Globex — Support renewal', amount: 12000, stage: 'Negotiation', accountId: '1', closeDate: '2026-07-28' },
    { id: 'o3', name: 'Initech — Migration', amount: 30000, stage: 'Qualification', accountId: '2' },
  ]);

  account = computed<Account | undefined>(() => this.accounts().find((a) => a.id === this.id()));
  contacts = computed(() => this.relatedContacts().filter((c) => c.accountId === this.id()));
  opportunities = computed(() => this.relatedOpportunities().filter((o) => o.accountId === this.id()));

  editing = signal(false);
  form = this.fb.group({
    name: ['', Validators.required],
    industry: ['', Validators.required],
    website: [''],
    phone: [''],
  });

  stageLabel(key: string): string {
    return this.stages.find((s) => s.key === key)?.label ?? key;
  }

  startEdit(): void {
    const a = this.account();
    if (!a) return;
    this.form.patchValue({
      name: a.name,
      industry: a.industry,
      website: a.website ?? '',
      phone: a.phone ?? '',
    });
    this.editing.set(true);
  }

  cancelEdit(): void {
    this.editing.set(false);
  }

  save(): void {
    if (this.form.invalid) return;
    const v = this.form.value;
    this.accounts.update((list) =>
      list.map((a) =>
        a.id === this.id()
          ? { ...a, name: v.name!, industry: v.industry!, website: v.website || undefined, phone: v.phone || undefined }
          : a,
      ),
    );
    this.editing.set(false);
  }
}
